options.systemMessage:
Du bist ein WhatsApp-Nachrichtenparser. Extrahiere aus der Benutzeranfrage folgende Informationen und gib sie als JSON zurück:

{
  "isGroup": true/false,
  "target": "Gruppenname" oder "Telefonnummer",
  "text": "Der zu sendende Nachrichtentext"
}

REGELN:
1. isGroup = true wenn der Benutzer "Gruppe" erwähnt oder einen Gruppennamen nennt
2. isGroup = false wenn eine Telefonnummer angegeben wird
3. target = Gruppenname (z.B. "Group Chat") ODER Telefonnummer (normalisiert ohne +, 00, Leerzeichen)
4. text = Der EXAKTE Nachrichtentext wie vom Benutzer formuliert

BEISPIELE:
"sende an +436601234567 mit 'Hi'" → {"isGroup": false, "target": "436601234567", "text": "Hi"}
"sende an Gruppe Family Group mit 'Hallo!'" → {"isGroup": true, "target": "Family Group", "text": "Hallo!"}
"schreib der Group Chat Gruppe 'Hey Leute'" → {"isGroup": true, "target": "Group Chat", "text": "Hey Leute"}
"sende eine Whatsapp Nachricht an die Gruppe \"Group Chat\" mit der Nachricht \"Hey wie geht's\"?" → {"isGroup": true, "target": "Group Chat", "text": "Hey wie geht's"}

Gib NUR das JSON zurück, keine zusätzlichen Erklärungen.

parameters.jsCode:
// Parse AI Agent output
const aiOutput = $json.output || '';

// Try to extract JSON from AI response
let parsed;
try {
  // Remove markdown code blocks if present
  const cleaned = aiOutput.replace(/```json\n?|```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse AI output as JSON: ${aiOutput}`);
}

const isGroup = parsed.isGroup === true;
const target = parsed.target || '';
const text = parsed.text || '';

if (!target || !text) {
  throw new Error('AI did not extract target and text correctly');
}

return {
  isGroup: isGroup,
  target: target,
  text: text,
  // For phone: normalize the number
  number: isGroup ? '' : target.replace(/[\s\+]/g, '').replace(/^00/, ''),
  // For group: store name for matching
  groupName: isGroup ? target.toLowerCase() : ''
};

const groupName = $('Parse AI Output').first().json.groupName;
const allChats = $json.body || $json;

// Filter for groups only (groups have JID ending with @g.us)
const groups = Array.isArray(allChats) ? allChats.filter(chat =>
  (chat.id || chat.jid)?.endsWith('@g.us')
) : [];

if (groups.length === 0) {
  throw new Error('Keine WhatsApp-Gruppen verfügbar. Ist WhatsApp verbunden?');
}

// Find matching group using partial match (case-insensitive)
const matchedGroup = groups.find(g =>
  (g.subject?.toLowerCase() || '').includes(groupName) ||
  (g.name?.toLowerCase() || '').includes(groupName)
);

if (!matchedGroup) {
  const availableGroups = groups.map(g => g.subject || g.name).filter(Boolean).join(', ');
  throw new Error(`Gruppe "${groupName}" wurde nicht gefunden. Verfügbare Gruppen: ${availableGroups || '(keine)'}`);
}

// Return the group JID (format: 120363xxx@g.us)
return {
  number: matchedGroup.id || matchedGroup.jid,
  text: $('Parse AI Output').first().json.text,
  groupFound: true,
  groupName: matchedGroup.subject || matchedGroup.name
};
